const _fmtDNum = n => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",minimumFractionDigits:0,maximumFractionDigits:0}).format(n);
const fmtD = n => window.__ZT_MASK__!==false ? "$ ●●●,●●●" : _fmtDNum(n);
