  const [crmNotes, setCrmNotes]         = useState(CRM_NOTES_SEED);
  const [crmOrders, setCrmOrders]       = useState(CRM_ORDERS_SEED);
  const [loaded, setLoaded] = useState(false);
  const [lastSaved, setLastSaved] = useState(null);
  const [maskPII, setMaskPII] = useState(true); // PII masked by default for safety
  const maskVal = (val, type="name") => {
    if(!maskPII) return val||"";
    if(!val || val==="—" || val==="") return val||"";
    if(type==="email") return String(val).replace(/^(.{2})[^@]*(@.*)$/, "$1***$2");
    if(type==="phone") return "●●●-●●●-●●●●";
    if(type==="ssn")   return "***-**-" + String(val).slice(-4);
    if(type==="taxid") return "**-***" + String(val).slice(-4);
    if(type==="amount"||type==="salary") return "$ ●●●,●●●";
    if(type==="name")  return String(val).split(" ").map((w,i)=>i===0?w:w[0]+"***").join(" ");
    if(type==="account") return "****" + String(val).slice(-4);
    return "●●●●●●";
  };
  const [appSettings, setAppSettings] = useState({
    ownerName: "Manju",
    ownerEmail: "manju@ziksatech.com",
    companyName: "Ziksatech, LLC",
    companyWebsite: "ziksatech.com",
    fiscalYearStart: "January",
    defaultBillRate: 150,
    currency: "USD",
    timezone: "America/Chicago",
  });
  const [colorMode, setColorMode]       = useState('dark'); // 'dark' | 'light'
  const [cmdOpen,    setCmdOpen]        = useState(false);
  const [cmdQuery,   setCmdQuery]       = useState("");
  const [globalSearch, setGlobalSearch] = useState("");
  const [searchOpen, setSearchOpen] = useState(false);
  const [saveStatus, setSaveStatus] = useState("idle"); // idle | saving | saved | error
  const [backupModal, setBackupModal] = useState(false);
  // Prevent auto-save from overwriting Supabase data on initial load
  const skipSaveRef = useRef(true);
  // Collapsible sidebar groups — Finance collapsed by default (10 items)
  const [collapsedGroups, setCollapsedGroups] = useState(() => {
    try { return JSON.parse(localStorage.getItem("zt-collapsed-groups") || '["Finance"]'); }
    catch { return ["Finance"]; }
  });
  const toggleGroup = (group) => {
    setCollapsedGroups(prev => {
      const next = prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group];
      localStorage.setItem("zt-collapsed-groups", JSON.stringify(next));
      return next;
    });
  }; // true = skip, set to false after first load completes
  const [restoreError, setRestoreError] = useState("");
  const [restoreSuccess, setRestoreSuccess] = useState("");

